    // 4. Category Filter
    const matchesCategory = categoryFilter === "all" || 
      (ticket.category || "General").toLowerCase() === categoryFilter.toLowerCase();

    return matchesStatus && matchesSearch && matchesPriority && matchesCategory;
  });

